// This allows TypeScript to pick up the magic constants that's auto-generated by Forge's Vite
// plugin that tells the Electron app where to look for the Vite-bundled app code (depending on
// whether you're running in development or production).
declare const MAIN_WINDOW_VITE_DEV_SERVER_URL: string;
declare const MAIN_WINDOW_VITE_NAME: string;

interface MiruTimerState {
  context: {
    billable: boolean;
    notes: string;
    projectName: string;
    taskName: string;
  };
  elapsedMs: number;
  elapsedSeconds: number;
  formatted: string;
  idle: {
    durationMs: number;
    prompted: boolean;
  } | null;
  idleThresholdSeconds: number;
  running: boolean;
}

interface MiruSessionState {
  baseUrl: string;
  company: Record<string, unknown> | null;
  companyRole: string;
  currentWorkspaceId: number | string | null;
  lastSyncAt: string;
  signedIn: boolean;
  syncError: string;
  syncStatus: "error" | "local" | "offline" | "synced" | "syncing";
  user: Record<string, unknown> | null;
  workspaces: Array<{ id: number | string; name: string; logo?: string }>;
}

interface Window {
  miruApi: {
    getSession: () => Promise<MiruSessionState>;
    login: (payload: {
      baseUrl?: string;
      email: string;
      password: string;
    }) => Promise<MiruSessionState>;
    logout: () => Promise<MiruSessionState>;
    saveTimerEntry: (payload: {
      projectId?: number | string;
      userId?: number | string;
    }) => Promise<unknown>;
    signup: (payload: {
      baseUrl?: string;
      email: string;
      firstName?: string;
      lastName?: string;
      password: string;
    }) => Promise<MiruSessionState>;
    switchWorkspace: (
      workspaceId: number | string
    ) => Promise<MiruSessionState>;
    syncCurrentTimer: (
      action?: "pull" | "push"
    ) => Promise<{ session: MiruSessionState; timer: MiruTimerState }>;
  };
  nativeDialog: {
    confirmDeleteTimeEntry: () => Promise<boolean>;
    quitApp: () => Promise<void>;
  };
  miruTimer: {
    applyIdleAction: (
      action: "remove-continue" | "remove-start-new" | "ignore-continue"
    ) => Promise<MiruTimerState>;
    forceIdleForTesting?: (durationMs: number) => Promise<MiruTimerState>;
    getState: () => Promise<MiruTimerState>;
    onStateChange: (callback: (state: MiruTimerState) => void) => () => void;
    pause: () => Promise<MiruTimerState>;
    reset: () => Promise<MiruTimerState>;
    setContext: (context: {
      billable: boolean;
      notes: string;
      projectName: string;
      taskName: string;
    }) => Promise<MiruTimerState>;
    setIdleThreshold: (seconds: number) => Promise<MiruTimerState>;
    start: () => Promise<MiruTimerState>;
    toggle: () => Promise<MiruTimerState>;
  };
}
